// Emit kernel/src/fixtures_gen.mbt — each fixture's plan.json embedded as a
// MoonBit `String` constant, so `moon test` needs no filesystem access.
//
// DO NOT EDIT the generated output by hand. Regenerate with:
//   kernel/tools/gen-fixtures.sh
//
// Source of truth: tests/fixtures/{valid,invalid}/*/plan.yaml
//   -> plan.json (via js-yaml, see gen-fixtures.sh) -> this .mbt file.
import { readFileSync, writeFileSync, readdirSync } from "node:fs";
import { join } from "node:path";

const root = join(import.meta.dirname, "..", "..");
const groups = ["valid", "invalid"];

const fixtures = [];
for (const group of groups) {
  const base = join(root, "tests/fixtures", group);
  for (const name of readdirSync(base)) {
    const planJson = join(base, name, "plan.json");
    let raw;
    try {
      raw = readFileSync(planJson, "utf8");
    } catch {
      continue; // no plan.json (run gen-fixtures.sh first)
    }
    fixtures.push({ name, group, raw });
  }
}
fixtures.sort((a, b) => a.name.localeCompare(b.name));

const ident = (s) => s.replace(/[^a-zA-Z0-9]/g, "_");

let out = "";
out += "// GENERATED by kernel/tools/gen-fixtures.sh — DO NOT EDIT.\n";
out += "// Source of truth: tests/fixtures/{valid,invalid}/*/plan.yaml\n";
out += "// (plan.yaml -> plan.json via js-yaml -> embedded here as String constants).\n";
out += "// Each constant is the fixture plan as JSON in the user-facing plan-schema\n";
out += "// shape (snake_case field names, per DECISIONS.md D16).\n\n";

for (const f of fixtures) {
  // Normalize via a JSON round-trip so the embedded text is stable/minified.
  const json = JSON.stringify(JSON.parse(f.raw));
  // JSON.stringify of the JSON text yields a valid double-quoted, escaped
  // string literal that MoonBit accepts verbatim.
  out += `///|\n`;
  out += `/// ${f.group}/${f.name} plan (see tests/fixtures/${f.group}/${f.name}/plan.yaml).\n`;
  out += `pub let ${ident(f.name)}_plan_json : String = ${JSON.stringify(json)}\n\n`;
}

writeFileSync(join(root, "kernel/src/fixtures_gen.mbt"), out);
console.log(`wrote kernel/src/fixtures_gen.mbt (${fixtures.length} fixtures)`);
